import base64, os

FILES = {
    "app.py": "",
    "utils/question_detector.py": "",
}

for rel_path, b64_data in FILES.items():
    os.makedirs(os.path.dirname(rel_path) if os.path.dirname(rel_path) else '.', exist_ok=True)
    with open(rel_path, 'wb') as f:
        f.write(base64.b64decode(b64_data))
    print(f"\u2705 {rel_path} \u5df2\u66f4\u65b0")

print("\U0001f389 \u66f4\u65b0\u5b8c\u6210\uff01\u8acb\u57f7\u884c: py -m streamlit run app.py")
